#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 505;
const int K = 305;
struct node{LL val,st,mxp;}a[N];
LL n,MOD,Ans;
LL dp[K][K],f1[K][K],f2[K][K];
LL p[]={0,2,3,5,7,11,13,17,19};
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void init_(node &A){
    LL tmp=A.val;
    for(int i=1;i<=8;i++){
        if(tmp%p[i])continue;
        A.st|=(1<<i-1);
        while(tmp%p[i]==0)tmp/=p[i];
    }if(tmp>1)A.mxp=tmp;
    return;
}
bool cmp(node d1,node d2){return d1.mxp<d2.mxp;}
void copy_(LL (&A)[K][K],LL (&B)[K][K]){
    for(int i=0;i<(1<<8);i++)
        for(int j=0;j<(1<<8);j++)A[i][j]=B[i][j];
    return;
}
void add(LL &x,LL y){x=(x+y)%MOD;return;}
int main(){
    n=read(),MOD=read();
    for(int i=1;i<n;i++)
        a[i].val=i+1,init_(a[i]);
    sort(a+1,a+n,cmp);
    dp[0][0]=1;
    for(int i=1;i<n;i++){
        if(i==1||a[i].mxp!=a[i-1].mxp||!a[i].mxp)
            copy_(f1,dp),copy_(f2,dp);
        for(int x=(1<<8)-1;x>=0;x--)
            for(int y=(1<<8)-1;y>=0;y--){
                if(x&y)continue;
                if(!(a[i].st&x))add(f2[x][a[i].st|y],f2[x][y]);
                if(!(a[i].st&y))add(f1[x|a[i].st][y],f1[x][y]);
            }
        if(i==n-1||a[i].mxp!=a[i+1].mxp||!a[i].mxp)
            for(int x=0;x<(1<<8);x++)
                for(int y=0;y<(1<<8);y++)
                    if(!(x&y))dp[x][y]=(f1[x][y]+f2[x][y]-dp[x][y]+MOD)%MOD;
    }
    for(int x=0;x<(1<<8);x++)
        for(int y=0;y<(1<<8);y++)
            if(!(x&y))add(Ans,dp[x][y]);
    cout<<Ans<<"\n";
    return 0;
}
